protected PurchPackingSlipHeaderTmp initializeProductReceiptHeader()
{
    PurchPackingSlipHeaderTmp purchPackingSlipHeaderTmpCreated = next initializeProductReceiptHeader();

    FWFTextBlockReportTextInit::newParameters(purchPackingSlipHeaderTmpCreated, this.parmVendPackingSlipJour()).addTexts();

    return purchPackingSlipHeaderTmpCreated;
}

protected PurchPackingSlipTmp initializeProductReceiptLine(PurchPackingSlipHeaderTmp _purchPackingSlipHeaderTmp, PurchPackingSlipDPReceiptLineQuerySelection _receiptLineSelection)
{
    PurchPackingSlipTmp purchPackingSlipTmpCreated = next initializeProductReceiptLine(_purchPackingSlipHeaderTmp, _receiptLineSelection);

    FWFTextBlockReportTextInit::newParameters(purchPackingSlipTmpCreated, _receiptLineSelection.parmVendPackingSlipTrans()).addTexts();

    return purchPackingSlipTmpCreated;
}
